import React, { useState, useEffect, useCallback } from 'react';
import { api } from '../services/api'; 
import { useAuth } from '../context/AuthContext';
import { CheckCircle, Truck, Loader2, Bike, Store, XCircle, AlertTriangle } from 'lucide-react';

const MisPedidosCliente = () => {
  const [pedidos, setPedidos] = useState([]);
  const [loading, setLoading] = useState(true);
  const [progresoEnvio, setProgresoEnvio] = useState({}); 
  const { user } = useAuth();

  const fetchPedidos = useCallback(async () => {
    try {
      setLoading(true);
      const clienteId = user?.id || user?._id;
      if (!clienteId) return;
      const data = await api.getPedidosCliente(clienteId);
      setPedidos(Array.isArray(data) ? data : []);
    } catch (error) {
      console.error("Error:", error);
    } finally {
      setLoading(false);
    }
  }, [user]);

  useEffect(() => {
    if (user) fetchPedidos();
  }, [user, fetchPedidos]);

  // TEMPORIZADOR AUTOMÁTICO DE 40 SEGUNDOS
  useEffect(() => {
    const intervals = [];
    pedidos.forEach(pedido => {
      const estado = pedido.estado?.toLowerCase().trim();
      
      // Si el pedido está en camino y la barra no llegó a 100, arranca
      if (estado === 'camino' && (!progresoEnvio[pedido._id] || progresoEnvio[pedido._id] < 100)) {
        const interval = setInterval(() => {
          setProgresoEnvio(prev => {
            const actual = prev[pedido._id] || 0;
            if (actual >= 100) {
              clearInterval(interval);
              return prev;
            }
            return { ...prev, [pedido._id]: actual + 1 };
          });
        }, 400); 
        intervals.push(interval);
      }
    });
    return () => intervals.forEach(id => clearInterval(id));
  }, [pedidos, progresoEnvio]);

  const handleCancelar = async (pedidoId) => {
    if (!window.confirm("¿Deseas cancelar este pedido? El stock será devuelto.")) return;
    try {
      await api.cancelarPedido(pedidoId);
      fetchPedidos(); 
    } catch (err) {
      alert("Error: " + err.message);
    }
  };

  if (loading) return <div style={msgContainer}><Loader2 className="animate-spin" /></div>;

  return (
    <div style={container}>
      <h2 style={title}>Seguimiento de Entrega</h2>
      <div style={listContainer}>
        {pedidos.map((pedido) => {
          const estado = pedido.estado?.toLowerCase().trim();
          const p = progresoEnvio[pedido._id] || (estado === 'completado' ? 100 : 0);
          
          // Solo permitimos cancelar si la barra lleva menos del 15% (apenas salió)
          const puedeCancelar = estado === 'camino' && p < 15;

          return (
            <div key={pedido._id} style={orderCard}>
              <div style={orderHeader}>
                <span style={dateText}>ID: {pedido._id?.slice(-6).toUpperCase()}</span>
                <span style={statusText}>{p >= 100 ? 'ENTREGADO' : 'EN CAMINO'}</span>
              </div>

              {estado !== 'cancelado' && (
                <div style={stepperWrapper}>
                  <div style={stepperBackground}>
                    <div style={{ ...stepperFill, width: `${p}%`, transition: 'width 0.4s linear' }} />
                  </div>
                  <div style={nodesContainer}>
                    <div style={nodeGroup}><Store size={14}/><span style={nodeLabel}>Local</span></div>
                    <div style={nodeGroup}><Bike size={14}/><span style={nodeLabel}>Reparto</span></div>
                    <div style={nodeGroup}><CheckCircle size={14}/><span style={nodeLabel}>Llegó</span></div>
                  </div>
                </div>
              )}

              <div style={bodyCard}>
                <h4 style={localName}>{pedido.local?.nombre}</h4>
                {puedeCancelar && (
                  <button onClick={() => handleCancelar(pedido._id)} style={cancelButton}>
                    <XCircle size={14} /> Cancelar (Devolver Stock)
                  </button>
                )}
                {p >= 15 && p < 100 && <p style={infoMsg}>El pedido está muy cerca, no se puede cancelar.</p>}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

// Estilos resumidos para brevedad (los mismos que tenías)
const container = { padding: '20px', maxWidth: '500px', margin: '0 auto' };
const title = { fontWeight: '900', marginBottom: '20px' };
const listContainer = { display: 'flex', flexDirection: 'column', gap: '15px' };
const orderCard = { background: '#fff', borderRadius: '15px', border: '1px solid #eee', overflow: 'hidden' };
const orderHeader = { padding: '10px 15px', display: 'flex', justifyContent: 'space-between', background: '#f9f9f9' };
const dateText = { fontSize: '0.7rem', color: '#888' };
const statusText = { fontSize: '0.7rem', fontWeight: 'bold', color: '#3182ce' };
const stepperWrapper = { padding: '30px 40px', position: 'relative' };
const stepperBackground = { height: '4px', background: '#eee', borderRadius: '10px' };
const stepperFill = { height: '100%', background: '#3182ce' };
const nodesContainer = { position: 'absolute', top: '22px', left: '40px', right: '40px', display: 'flex', justifyContent: 'space-between' };
const nodeGroup = { display: 'flex', flexDirection: 'column', alignItems: 'center' };
const nodeLabel = { fontSize: '0.5rem', marginTop: '4px' };
const bodyCard = { padding: '15px' };
const localName = { margin: 0, fontSize: '1rem' };
const cancelButton = { marginTop: '10px', width: '100%', padding: '8px', border: 'none', background: '#fff1f2', color: '#e11d48', borderRadius: '8px', cursor: 'pointer', fontSize: '0.8rem', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '5px' };
const infoMsg = { fontSize: '0.7rem', color: '#888', textAlign: 'center', marginTop: '10px' };
const msgContainer = { textAlign: 'center', padding: '50px' };

export default MisPedidosCliente;
